  "丁":{name:"Yin Fire — The Candle Flame",arch:"Artist / Intimate Illuminator",core:"You are candlelight — warm, intimate, and illuminating in a way that draws people close rather than dazzling from afar. More introspective than Yang Fire, you work beautifully one-on-one and create warmth in close relationships. Highly intuitive, artistic, and quietly powerful.",strengths:["Deeply artistic and aesthetically gifted","Warm and intimate — people trust you quickly","Highly intuitive and perceptive","Quietly determined beneath a gentle exterior","Creates loyal, lasting connections"],challenges:["Emotionally volatile beneath the surface","Sensitivity to rejection cuts deeply","May burn low when unappreciated","Tendency to deplete giving to others"],strengthen:{el:["Wood","Fire"],avoid:["Water","Excessive Metal"],colors:["Deep red","Warm orange","Purple","Green"],dirs:["South","East"],foods:["Bitter foods","Red fruits","Dark chocolate","Warming spices"],advice:"Protect your creative time fiercely. Your art is your medicine."},organ:"Heart & Small Intestine",emotion:"Emotional sensitivity / Fragility",healthRisk:"Emotional exhaustion, heart sensitivity, blood circulation issues, anxiety.",career:"Art, music, writing, counselling, healing arts, design, spiritual work"},
